from flask import Flask, request, jsonify
import pickle
import os
import time

app = Flask(__name__)
CACHE_DIR = 'cache'
EXPIRATION_TIME = 3600  # 1 hour in seconds

def load_cache():
    if not os.path.exists(CACHE_DIR):
        os.makedirs(CACHE_DIR)

def save_to_cache(key, data):
    with open(os.path.join(CACHE_DIR, key), 'wb') as f:
        pickle.dump(data, f)

def load_from_cache(key):
    cache_file = os.path.join(CACHE_DIR, key)
    if not os.path.exists(cache_file):
        return None
    with open(cache_file, 'rb') as f:
        data = pickle.load(f)
    if time.time() - data['timestamp'] > EXPIRATION_TIME:
        os.remove(cache_file)
        return None
    return data['data']

@app.route('/api', methods=['GET'])
def api():
    key = request.args.get('key')
    cached_data = load_from_cache(key)
    if cached_data is not None:
        return jsonify(cached_data), 200

    # Simulate expensive API response
    expensive_response = {
        'data': {
            'nested': {'value': 42},
            'list': [1, 2, 3],
            'metadata': {'timestamp': time.time()}
        }
    }

    save_to_cache(key, expensive_response)
    return jsonify(expensive_response), 200

if __name__ == '__main__':
    load_cache()
    app.run(debug=True)